## Task 9: 驾驶舱入口 Controller

**File to create:** `src/main/java/com/yottastudios/ns/collabspace/space/controller/SpaceChangeRecordController.java`

```java
package com.yottastudios.ns.collabspace.space.controller;

import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
import com.yottastudios.ns.collabspace.shared.util.page.PageInfo;
import com.yottastudios.ns.collabspace.space.manager.query.SpaceChangeRecordQueryManager;
import com.yottastudios.ns.collabspace.space.ro.SpaceChangeRecordPageRo;
import com.yottastudios.ns.collabspace.space.vo.SpaceChangeRecordVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import org.springframework.web.bind.annotation.RestController;

@RestController
@Tag(name = "Space Change Record")
@ApiResource(path = "/space/changeRecord")
public class SpaceChangeRecordController {

    @Resource
    private SpaceChangeRecordQueryManager spaceChangeRecordQueryManager;

    @GetResource(path = "/page", requiredSpaceAdmin = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "分页查询空间站变更记录")
    public ResponseData<PageInfo<SpaceChangeRecordVo>> page(SpaceChangeRecordPageRo ro) {
        String spaceId = SpaceHolder.get();
        PageInfo<SpaceChangeRecordVo> result = spaceChangeRecordQueryManager.page(
                spaceId, ro.getType(), ro.getPageNum(), ro.getPageSize());
        return ResponseData.success(result);
    }
}
```

